import * as __autkDbMod from '@urban-toolkit/autk-db';
const AutkSpatialDb = __autkDbMod.AutkDb || __autkDbMod.AutkSpatialDb;

// The merge delivers [osmLayers, rasterFc]:
//   arg[0] = OSM layer array (EPSG:4326) from niteroi-osm
//   arg[1] = single-row FeatureCollection carrying the GeoTIFF bytes (base64)
// Depending on how the merge output was resolved it can also arrive as a
// { data: [...] } 'outputs' wrapper — accept either, and if it is neither,
// throw an error that reports the ACTUAL shape so the pipeline is debuggable.
const __shape = (v) => v == null ? ('' + v)
  : Array.isArray(v) ? ('array[' + v.length + ']')
  : (typeof v === 'object') ? ('object{' + Object.keys(v).slice(0, 8).join(',') + '}')
  : typeof v;
let __parts = (arg && !Array.isArray(arg) && Array.isArray(arg.data)) ? arg.data : arg;
if (!Array.isArray(__parts)) {
    throw new Error('[join] expected a 2-element merge array, got arg=' + __shape(arg)
        + (arg && typeof arg === 'object' && 'dataType' in arg ? ' dataType=' + arg.dataType : ''));
}
const [osmLayers, rasterFc] = __parts;
if (!Array.isArray(osmLayers)) {
    throw new Error('[join] osmLayers is not an array — arg=' + __shape(arg)
        + ' parts[0]=' + __shape(__parts[0])
        + (__parts[0] && typeof __parts[0] === 'object' && 'dataType' in __parts[0]
            ? ' (a ref: dataType=' + __parts[0].dataType + ') — the sandbox did not resolve the merge refs; restart the sandbox so the worker.py fix is live'
            : ''));
}
const geotiffB64 = rasterFc?.features?.[0]?.properties?.geotiff_b64;
if (!geotiffB64) throw new Error('geotiff_b64 missing from upstream raster row');

// Decode the base64-embedded raster bytes back into a clean ArrayBuffer
// (slicing off any Buffer prefix so loadGeoTiff sees just the raster).
const nodeBuf = Buffer.from(geotiffB64, 'base64');
const geotiffArrayBuffer = nodeBuf.buffer.slice(
    nodeBuf.byteOffset,
    nodeBuf.byteOffset + nodeBuf.byteLength,
);

const BAND_COUNT = 24;

const db = new AutkSpatialDb();
await db.init();

// Re-ingest each OSM layer (already in EPSG:4326) as a custom table and
// project to EPSG:3395 so the metric NEAR distance works.
for (const layer of osmLayers) {
    await db.loadCustomLayer({
        geojsonObject: layer.geojson,
        outputTableName: layer.name,
        coordinateFormat: 'EPSG:3395',
        layerType: layer.type,
    });
}

// Reuse the bytes the Python DataLoading node already fetched — no second
// HTTP request, no URL needed here.
await db.loadGeoTiff({
    geotiffArrayBuffer,
    outputTableName: 'lst',
    sourceCrs: 'EPSG:4326',
    coordinateFormat: 'EPSG:3395',
});

// Spatial join: average each LST band within 1 km of every road segment.
await db.spatialQuery({
    tableRootName: 'table_osm_roads',
    tableJoinName: 'lst',
    spatialPredicate: 'NEAR',
    nearDistance: 1000,
    output: { type: 'MODIFY_ROOT' },
    joinType: 'LEFT',
    groupBy: {
        selectColumns: Array.from({ length: BAND_COUNT }, (_, i) => ({
            tableName: 'lst',
            column: `band_${i + 1}`,
            aggregateFn: 'avg',
            aggregateFnResultColumnName: `band_${i + 1}`,
        })),
    },
});

// Reshape per-band averages into a single lst_timeseries array per road.
const bandSelects = Array.from({ length: BAND_COUNT }, (_, i) =>
    `COALESCE(json_extract(properties, '$.sjoin.avg.band_${i + 1}')::DOUBLE, 0)`
).join(', ');

await db.rawQuery({
    query: `
        SELECT
            geometry,
            json_merge_patch(
                COALESCE(CAST(properties AS JSON), '{}'::JSON),
                json_object('lst_timeseries', [${bandSelects}])
            ) AS properties
        FROM table_osm_roads
    `,
    output: { type: 'CREATE_TABLE', tableName: 'table_osm_roads', source: 'osm', tableType: 'roads' },
});

// Rebuild the layer array uniformly from the local db (all in EPSG:3395)
// so the downstream map gets a consistent CRS across surface/parks/water/roads.
// The LST raster is intentionally not re-emitted: it is only needed for the
// join above, the map skips it, and its non-FeatureCollection shape would be
// dropped by the grammar resolver anyway.
const layers = [];
for (const layer of osmLayers) {
    layers.push({
        name: layer.name,
        type: layer.type,
        geojson: await db.getLayer(layer.name),
    });
}

return layers;

{
  "compute": [
    {
      "dataRef": "table_osm_roads",
      "attributes": {
        "bands": "lst_timeseries"
      },
      "attributeArrays": {
        "bands": 24
      },
      "outputColumns": [
        "angle",
        "intercept"
      ],
      "wglsFunction": "
  var n = f32(bands_length);
  var sum_x  = 0.0;
  var sum_y  = 0.0;
  var sum_xy = 0.0;
  var sum_x2 = 0.0;

  for (var i = 0u; i < bands_length; i++) {
    let x   = f32(i);
    let y   = bands[i];
    sum_x  += x;
    sum_y  += y;
    sum_xy += x * y;
    sum_x2 += x * x;
  }

  let denom = n * sum_x2 - sum_x * sum_x;
  var slope     = 0.0;
  var intercept = 0.0;
  if (denom != 0.0) {
    slope     = (n * sum_xy - sum_x * sum_y) / denom;
    intercept = (sum_y - slope * sum_x) / n;
  }

  var out: OutputArray;
  out[0] = atan(slope) * (180.0 / 3.14159265358979);
  out[1] = intercept;
  return out;
"
    }
  ]
}

{
  "plot": {
    "dataRef": "table_osm_roads",
    "mark": "scatter",
    "axis": [
      "intercept",
      "angle"
    ],
    "title": "LST regression — warming angle vs baseline (Niterói roads)",
    "events": [
      "brush"
    ]
  }
}
